注解 作用 限定 <code>@OnLoad("name")</code> 插件或扩展加载时调用。有 name 参数时可被 <code>@Route</code>/<code>@Cmd</code>/<code>@Passive</code> 的 onLoad 引用 函数必须零参数，可 suspend <code>@OnUnload("name")</code> 插件或扩展卸载时调用。与 <code>@OnLoad</code> 配对使用 函数必须零参数，可 suspend <code>@OnStart</code> Plugin.start() 时调用 每个插件最多一个；必须零参数，可 suspend <code>@OnStop</code> Plugin.stop() 时调用 每个插件最多一个；必须零参数，可 suspend <p><code>@OnLoad()</code> 无 name 参数时为全局 onLoad，所有扩展都会调用； <code>@OnLoad("name")</code> 为命名 onLoad，仅被引用它的扩展调用。</p> <pre><code>@OnLoad("init_config")
suspend fun initConfig() {
    val config = useConfig()
    // 加载配置
}

@OnUnload("cleanup_config")
suspend fun cleanupConfig() {
    // 清理配置
}

// 此 Route 扩展加载时会自动调用 initConfig()，卸载时调用 cleanupConfig()
@Route(
    path = "MY_FEATURE",
    method = "...",
    onLoad = ["init_config"],
    onUnload = ["cleanup_config"]
)
suspend fun myFeature(meta: Meta) { ... }
</code></pre>

@Route -- Route Extension @Cmd -- Command Extension @Passive -- Passive Extension @LLMTool -- LLM Tool @OnLoad / @OnUnload -- Lifecycle <pre><code>@Route(method = "GET", path = "/api/hello")
suspend fun helloRoute() {
    val http = useHttp()
    // Handle request
}
</code></pre> <pre><code>@Cmd(name = "hello", alias = ["hi", "hey"])
suspend fun helloCommand() {
    val meta = useMeta()
    val llm = useLLM()
    // Handle command
}
</code></pre> <pre><code>@Passive
suspend fun backgroundTask() {
    val scheduler = useScheduler()
    scheduler.scheduleRecurrently("bg", "0 */1 * * *") {
        // Periodic execution
    }
}
</code></pre> <pre><code>@LLMTool(name = "search_images", set = "default")
@LLMDesc("Search for images based on a query string")
suspend fun searchImages(
    @LLMDesc("The search query") query: String
): String {
    // Implement search logic
    return "results..."
}
</code></pre> <pre><code>@OnLoad
suspend fun init() {
    // Executed when plugin loads
    val config = useConfig()
}

@OnUnload
suspend fun cleanup() {
    // Cleanup when plugin unloads
}
</code></pre>

AgentExtensionRouteExtensionCmdExtensionPassiveExtension <pre><code>class MyAgentExt : AgentExtension&lt;MyPlugin&gt; {
    override fun onLoad(context: PluginContext) {
        // Initialize: register scheduled tasks, tools, routes, etc.
        context.scheduler.scheduleRecurrently("my-task", "0 */1 * * *") {
            // Runs every hour
        }
    }

    override fun onUnload() {
        // Clean up resources
    }
}
</code></pre> <pre><code>class MyRouteExt : RouteExtension&lt;MyPlugin&gt; {
    // LLM matches this extension based on matcher key and value
    override val matcher: Pair&lt;String, String&gt;
        get() = "image" to "Generate or search images"
}
</code></pre> <pre><code>class MyCmdExt : SlashCmdExtension&lt;MyPlugin&gt; {
    override val cmd: String = "hello"
    override val alias: List&lt;String&gt; = listOf("hi", "hey")

    override fun onLoad(context: PluginContext) {
        context.chain { meta -&gt;
            // Handle command logic
        }
    }
}
</code></pre> <pre><code>class MyPassiveExt : PassiveExtension&lt;MyPlugin&gt; {
    override fun onLoad(context: PluginContext) {
        context.scheduler.scheduleRecurrently("bg-task", "*/30 * * * *") {
            // Background periodic task
        }
    }
}
</code></pre>
